interface UserRepo     { String getUserEmail(String userId); }  // throws EntityNotFoundException if not found
interface BalanceService{ boolean hasFunds(String userId, double amount); }
interface PaymentGateway{ String charge(String userId, double amount); }  // throws on failure
interface ReceiptService{ void createReceipt(String chargeId, double amount); }
interface NotifySvc    { void notify(String email, String status); }
class EntityNotFoundException extends RuntimeException { EntityNotFoundException(String m) { super(m); } }

class RazorpayPaymentService {
    UserRepo userRepo; BalanceService balance;
    PaymentGateway gateway; ReceiptService receipts; NotifySvc notifySvc;

    String charge(String userId, double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Amount must be positive");
        String email    = userRepo.getUserEmail(userId);
        if (!balance.hasFunds(userId, amount)) throw new IllegalStateException("Insufficient funds");
        String chargeId;
        try {
            chargeId = gateway.charge(userId, amount);
            receipts.createReceipt(chargeId, amount);
            notifySvc.notify(email, "SUCCESS");
        } catch (Exception e) {
            notifySvc.notify(email, "FAILED");
            throw e;
        }
        return chargeId;
    }
}
