// (all interfaces and classes as above)
@ExtendWith(MockitoExtension.class)
class RazorpayPaymentServiceTest {
    @Mock UserRepo userRepo; @Mock BalanceService balance;
    @Mock PaymentGateway gateway; @Mock ReceiptService receipts; @Mock NotifySvc notifySvc;
    @InjectMocks RazorpayPaymentService service;
    @Captor ArgumentCaptor<Double> amountCaptor;

    private void setupHappyPath() throws Exception {
        when(userRepo.getUserEmail("U01")).thenReturn("aisha@example.com");
        when(balance.hasFunds("U01", 1500)).thenReturn(true);
        when(gateway.charge("U01", 1500)).thenReturn("CHG-001");
    }
    @Test void charge_success_fullPipelineExecuted() throws Exception {
        setupHappyPath();
        String chargeId = service.charge("U01", 1500);
        assertEquals("CHG-001", chargeId);
        verify(receipts).createReceipt("CHG-001", 1500);
        verify(notifySvc).notify("aisha@example.com", "SUCCESS");
    }
    @Test void charge_userNotFound_nothingElse() {
        when(userRepo.getUserEmail("U99")).thenThrow(new EntityNotFoundException("not found"));
        assertThrows(EntityNotFoundException.class, () -> service.charge("U99", 1500));
        verifyNoInteractions(balance, gateway, receipts, notifySvc);
    }
    @Test void charge_insufficientFunds_noChargeNoReceipt() throws Exception {
        when(userRepo.getUserEmail("U01")).thenReturn("aisha@example.com");
        when(balance.hasFunds("U01", 1500)).thenReturn(false);
        assertThrows(IllegalStateException.class, () -> service.charge("U01", 1500));
        verifyNoInteractions(gateway, receipts, notifySvc);
    }
    @Test void charge_gatewayFails_noReceipt_failureNotification() throws Exception {
        when(userRepo.getUserEmail("U01")).thenReturn("aisha@example.com");
        when(balance.hasFunds("U01", 1500)).thenReturn(true);
        when(gateway.charge("U01", 1500)).thenThrow(new RuntimeException("Gateway error"));
        assertThrows(RuntimeException.class, () -> service.charge("U01", 1500));
        verify(receipts, never()).createReceipt(any(), anyDouble());
        verify(notifySvc).notify("aisha@example.com", "FAILED");
    }
    @Test void charge_zeroAmount_throwsBeforeAnyCall() {
        assertThrows(IllegalArgumentException.class, () -> service.charge("U01", 0));
        verifyNoInteractions(userRepo, balance, gateway, receipts, notifySvc);
    }
    @Test void charge_capturesExactAmountPassedToGateway() throws Exception {
        setupHappyPath();
        service.charge("U01", 1500);
        verify(gateway).charge(eq("U01"), amountCaptor.capture());
        assertEquals(1500.0, amountCaptor.getValue(), 0.01);
    }
}
